import torch
import torch.nn as nn


class Adder(nn.Module):
    def __init__(self, in_dim=8):
        super().__init__()
        self.fc = nn.Linear(in_dim, in_dim)
        # BUG: bias created on CPU, model later moved to cuda
        self.bias = torch.zeros(in_dim)

    def forward(self, x):
        return self.fc(x) + self.bias


def infer(model, x):
    return model(x.to('cuda' if torch.cuda.is_available() else 'cpu'))


def main():
    model = Adder().to('cuda' if torch.cuda.is_available() else 'cpu')
    x = torch.randn(4, 8)
    out = infer(model, x)
    print(out.shape)


if __name__ == '__main__':
    main()
